"use client"

import {
  forwardRef,
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  type AnimationEvent,
  type CSSProperties,
  type HTMLAttributes,
  type ReactNode,
} from "react"

import "./border-beam.css"

export type BorderBeamSize = "sm" | "md" | "line"
export type BorderBeamTheme = "dark" | "light" | "auto"
export type BorderBeamColorVariant = "colorful" | "mono" | "ocean" | "sunset"

const useIsomorphicLayoutEffect =
  typeof window !== "undefined" ? useLayoutEffect : useEffect

export interface BorderBeamProps
  extends Omit<HTMLAttributes<HTMLDivElement>, "children"> {
  children: ReactNode
  size?: BorderBeamSize
  colorVariant?: BorderBeamColorVariant
  theme?: BorderBeamTheme
  active?: boolean
  borderRadius?: number
  staticColors?: boolean
  duration?: number
  strength?: number
  brightness?: number
  saturation?: number
  hueRange?: number
  onActivate?: () => void
  onDeactivate?: () => void
}

const SIZE_DEFAULT_RADIUS: Record<BorderBeamSize, number> = {
  sm: 18,
  md: 16,
  line: 16,
}

function useSystemTheme(enabled: boolean): "dark" | "light" {
  const [sysTheme, setSysTheme] = useState<"dark" | "light">(() => {
    if (typeof window === "undefined") return "dark"
    return window.matchMedia("(prefers-color-scheme: dark)").matches
      ? "dark"
      : "light"
  })

  useEffect(() => {
    if (!enabled) return
    const mq = window.matchMedia("(prefers-color-scheme: dark)")
    setSysTheme(mq.matches ? "dark" : "light")
    const handler = (e: MediaQueryListEvent) =>
      setSysTheme(e.matches ? "dark" : "light")
    mq.addEventListener("change", handler)
    return () => mq.removeEventListener("change", handler)
  }, [enabled])

  return sysTheme
}

export const BorderBeam = forwardRef<HTMLDivElement, BorderBeamProps>(
  function BorderBeam(
    {
      children,
      size = "md",
      colorVariant = "colorful",
      theme,
      active = true,
      borderRadius,
      staticColors = false,
      duration,
      strength = 1,
      brightness = 1.3,
      saturation,
      hueRange = 30,
      className,
      style,
      onActivate,
      onDeactivate,
      onAnimationEnd: consumerOnAnimationEnd,
      ...rest
    },
    forwardedRef
  ) {
    const internalRef = useRef<HTMLDivElement | null>(null)
    const [phase, setPhase] = useState<"idle" | "active" | "fading">(
      active ? "active" : "idle"
    )
    const [detectedRadius, setDetectedRadius] = useState<number | null>(null)

    const systemTheme = useSystemTheme(theme === "auto")
    const resolvedTheme = theme === "auto" ? systemTheme : (theme ?? "dark")

    useIsomorphicLayoutEffect(() => {
      if (borderRadius != null) return
      const child = internalRef.current?.firstElementChild as HTMLElement | null
      if (!child) return
      const r = parseFloat(getComputedStyle(child).borderTopLeftRadius)
      if (!Number.isNaN(r) && r > 0) setDetectedRadius(r)
    }, [borderRadius, children])

    useEffect(() => {
      if (active && phase !== "active") setPhase("active")
      else if (!active && phase === "active") setPhase("fading")
    }, [active, phase])

    const handleAnimationEnd = useCallback(
      (e: AnimationEvent<HTMLDivElement>) => {
        if (e.target !== e.currentTarget) {
          consumerOnAnimationEnd?.(e)
          return
        }
        const name = e.animationName
        if (name.includes("fade-out")) {
          setPhase("idle")
          onDeactivate?.()
        } else if (name.includes("fade-in")) {
          onActivate?.()
        }
        consumerOnAnimationEnd?.(e)
      },
      [onActivate, onDeactivate, consumerOnAnimationEnd]
    )

    const setRefs = useCallback(
      (node: HTMLDivElement | null) => {
        internalRef.current = node
        if (typeof forwardedRef === "function") forwardedRef(node)
        else if (forwardedRef) forwardedRef.current = node
      },
      [forwardedRef]
    )

    const finalRadius =
      borderRadius ?? detectedRadius ?? SIZE_DEFAULT_RADIUS[size]
    const finalStaticColors = colorVariant === "mono" || staticColors
    const clampedStrength = Math.max(0, Math.min(1, strength))
    const finalDuration = duration ?? (size === "line" ? 2.4 : 1.96)
    const finalHueRange = size === "line" ? Math.min(hueRange, 13) : hueRange

    // Detune breath/spike against the travel period to avoid visible resonance.
    const breatheDuration = finalDuration * 1.3
    const spikeDuration = finalDuration * 1.33
    const spike2Duration = finalDuration * 1.7

    const beamStyle: CSSProperties = {
      ...style,
      ["--beam-radius" as string]: `${finalRadius}px`,
      ["--beam-inner-radius" as string]: `${Math.max(0, finalRadius - 1)}px`,
      ["--beam-duration" as string]: `${finalDuration}s`,
      ["--beam-strength" as string]: clampedStrength,
      ["--beam-brightness" as string]: brightness,
      ["--beam-hue-range" as string]: `${finalHueRange}deg`,
      ...(saturation != null
        ? { ["--beam-saturation" as string]: saturation }
        : {}),
      ...(size === "line"
        ? {
            ["--beam-breathe-duration" as string]: `${breatheDuration.toFixed(2)}s`,
            ["--beam-spike-duration" as string]: `${spikeDuration.toFixed(2)}s`,
            ["--beam-spike2-duration" as string]: `${spike2Duration.toFixed(2)}s`,
          }
        : {}),
    }

    return (
      <div
        {...rest}
        ref={setRefs}
        className={className}
        style={beamStyle}
        data-beam=""
        data-size={size}
        data-variant={colorVariant}
        data-theme={theme != null ? resolvedTheme : undefined}
        data-static-colors={finalStaticColors ? "" : undefined}
        data-active={phase === "active" ? "" : undefined}
        data-fading={phase === "fading" ? "" : undefined}
        onAnimationEnd={handleAnimationEnd}
      >
        {children}
        <div data-beam-bloom />
      </div>
    )
  }
)

BorderBeam.displayName = "BorderBeam"

/*
 * border-beam.css — auto-generated by scripts/generate-css.mjs
 *
 * Refactored from Jakubantalik/border-beam (MIT) into static, registry-native CSS.
 * All per-instance @property names eliminated; multi-instance independence is
 * provided by the CSS standard (each element holds its own value of each
 * inheriting custom property).
 *
 * Supports border (sm/md) and line (bottom-only traveling glow) size variants.
 * Theme can be set per-component via data-theme="dark"|"light" attribute,
 * or inherited from the page's .dark class (default when no data-theme is set).
 *
 * To tweak palettes or stop positions, edit scripts/generate-css.mjs and rerun
 *   pnpm run generate:css
 */

@property --beam-angle {
  syntax: "<angle>";
  initial-value: 0deg;
  inherits: true;
}
@property --beam-opacity {
  syntax: "<number>";
  initial-value: 0;
  inherits: true;
}
@property --beam-x {
  syntax: "<number>";
  initial-value: 0;
  inherits: true;
}
@property --beam-w {
  syntax: "<number>";
  initial-value: 1;
  inherits: true;
}
@property --beam-h {
  syntax: "<number>";
  initial-value: 1;
  inherits: true;
}
@property --beam-spike {
  syntax: "<number>";
  initial-value: 1;
  inherits: true;
}
@property --beam-spike2 {
  syntax: "<number>";
  initial-value: 1;
  inherits: true;
}
@property --beam-edge {
  syntax: "<number>";
  initial-value: 1;
  inherits: true;
}

@keyframes beam-spin     { to { --beam-angle: 360deg; } }
@keyframes beam-fade-in  { to { --beam-opacity: 1; } }
@keyframes beam-fade-out { from { --beam-opacity: 1; } to { --beam-opacity: 0; } }
@keyframes beam-hue-shift {
  0%, 100% {
    filter: hue-rotate(calc(var(--beam-hue-range, 30deg) * -1))
            brightness(var(--beam-brightness, 1.3))
            saturate(var(--beam-saturation, 1));
  }
  50% {
    filter: hue-rotate(var(--beam-hue-range, 30deg))
            brightness(var(--beam-brightness, 1.3))
            saturate(var(--beam-saturation, 1));
  }
}
@keyframes beam-hue-shift-bloom {
  0%, 100% {
    filter: blur(8px) hue-rotate(calc(var(--beam-hue-range, 30deg) * -1 + 10deg))
            brightness(var(--beam-brightness, 1.3))
            saturate(var(--beam-saturation, 1));
  }
  50% {
    filter: blur(8px) hue-rotate(calc(var(--beam-hue-range, 30deg) + 10deg))
            brightness(var(--beam-brightness, 1.3))
            saturate(var(--beam-saturation, 1));
  }
}

@keyframes beam-travel {
  0%   { --beam-x: 0.06;  --beam-w: 0.5; }
  10%  { --beam-x: 0.15;  --beam-w: 0.8; }
  20%  { --beam-x: 0.25;  --beam-w: 1.1; }
  30%  { --beam-x: 0.35;  --beam-w: 1.3; }
  40%  { --beam-x: 0.44;  --beam-w: 1.45; }
  50%  { --beam-x: 0.5;   --beam-w: 1.5; }
  60%  { --beam-x: 0.56;  --beam-w: 1.45; }
  70%  { --beam-x: 0.65;  --beam-w: 1.3; }
  80%  { --beam-x: 0.75;  --beam-w: 1.1; }
  90%  { --beam-x: 0.85;  --beam-w: 0.8; }
  100% { --beam-x: 0.94;  --beam-w: 0.5; }
}

@keyframes beam-edge-fade {
  0%    { --beam-edge: 0; }
  12.5% { --beam-edge: 0; }
  32.5% { --beam-edge: 1; }
  67.5% { --beam-edge: 1; }
  87.5% { --beam-edge: 0; }
  100%  { --beam-edge: 0; }
}

@keyframes beam-breathe {
  0%, 100% { --beam-h: 0.8; }
  25%      { --beam-h: 1.25; }
  55%      { --beam-h: 0.85; }
  80%      { --beam-h: 1.3; }
}

@keyframes beam-spike {
  0%   { --beam-spike: 0.8; }
  25%  { --beam-spike: 1.3; }
  50%  { --beam-spike: 0.9; }
  75%  { --beam-spike: 1.4; }
  100% { --beam-spike: 0.8; }
}

@keyframes beam-spike2 {
  0%   { --beam-spike2: 1.2; }
  25%  { --beam-spike2: 0.7; }
  50%  { --beam-spike2: 1.4; }
  75%  { --beam-spike2: 0.8; }
  100% { --beam-spike2: 1.2; }
}

[data-beam] {
  position: relative;
  border-radius: var(--beam-radius, 16px);
  overflow: hidden;
}
[data-beam] [data-beam-bloom] {
  display: none;
}

/* ---- border/sm/md animation rules ---- */

[data-beam][data-active]:not([data-size="line"]) {
  animation:
    beam-spin var(--beam-duration, 1.96s) linear infinite,
    beam-fade-in 0.6s ease forwards;
}
[data-beam][data-fading]:not([data-size="line"]) {
  animation:
    beam-spin var(--beam-duration, 1.96s) linear infinite,
    beam-fade-out 0.5s ease forwards;
}

/* ---- line animation rules ---- */

[data-beam][data-size="line"][data-active] {
  animation:
    beam-travel var(--beam-duration, 2.4s) linear infinite,
    beam-edge-fade var(--beam-duration, 2.4s) linear infinite,
    beam-breathe var(--beam-breathe-duration, 3.12s) ease-in-out infinite,
    beam-spike var(--beam-spike-duration, 3.19s) ease-in-out infinite,
    beam-spike2 var(--beam-spike2-duration, 4.08s) ease-in-out infinite,
    beam-fade-in 0.6s ease forwards;
}
[data-beam][data-size="line"][data-fading] {
  animation:
    beam-travel var(--beam-duration, 2.4s) linear infinite,
    beam-edge-fade var(--beam-duration, 2.4s) linear infinite,
    beam-breathe var(--beam-breathe-duration, 3.12s) ease-in-out infinite,
    beam-spike var(--beam-spike-duration, 3.19s) ease-in-out infinite,
    beam-spike2 var(--beam-spike2-duration, 4.08s) ease-in-out infinite,
    beam-fade-out 0.5s ease forwards;
}

/* ---- variant overrides for opacity multiplier (mono is half-strength) ---- */

[data-beam][data-variant="mono"] {
  --beam-mono-multiplier: 0.5;
}
[data-beam] {
  --beam-mono-multiplier: 1;
}

/* ---- line-specific opacity overrides ---- */

[data-beam][data-size="line"] {
  --beam-stroke-opacity: 0.72;
  --beam-inner-opacity: 0.7;
  --beam-bloom-opacity: 0.8;
  --beam-inner-shadow: rgba(0, 0, 0, 0.14);
  --beam-saturation: 1.2;
}
.dark [data-beam][data-size="line"] {
  --beam-inner-shadow: rgba(255, 255, 255, 0.1);
}
[data-beam][data-size="line"][data-theme="dark"] {
  --beam-inner-shadow: rgba(255, 255, 255, 0.1);
  --beam-saturation: 1.2;
}
[data-beam][data-size="line"][data-theme="light"] {
  --beam-inner-shadow: rgba(0, 0, 0, 0.14);
  --beam-saturation: 1.2;
}

/* ---- mappings for the conic theme overlays (border/sm/md) ---- */

[data-beam] {
  --beam-conic-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 54%, rgba(0, 0, 0, 0.08) 57%, rgba(0, 0, 0, 0.2) 60%, rgba(0, 0, 0, 0.4) 63%, rgba(0, 0, 0, 0.55) 66%, rgba(0, 0, 0, 0.4) 69%, rgba(0, 0, 0, 0.2) 72%, rgba(0, 0, 0, 0.08) 75%, transparent 78%, transparent 100%);
  --beam-bloom-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 58%, rgba(0, 0, 0, 0.02) 62%, rgba(0, 0, 0, 0.08) 65%, rgba(0, 0, 0, 0.2) 67%, rgba(0, 0, 0, 0.4) 69%, rgba(0, 0, 0, 0.6) 70%, rgba(0, 0, 0, 0.6) 70.5%, rgba(0, 0, 0, 0.4) 71.5%, rgba(0, 0, 0, 0.2) 73%, rgba(0, 0, 0, 0.08) 75%, rgba(0, 0, 0, 0.03) 78%, transparent 82%);
}
.dark [data-beam] {
  --beam-conic-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 54%, rgba(255, 255, 255, 0.1) 57%, rgba(255, 255, 255, 0.3) 60%, rgba(255, 255, 255, 0.6) 63%, rgba(255, 255, 255, 0.75) 66%, rgba(255, 255, 255, 0.6) 69%, rgba(255, 255, 255, 0.3) 72%, rgba(255, 255, 255, 0.1) 75%, transparent 78%, transparent 100%);
  --beam-bloom-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 58%, rgba(255, 255, 255, 0.03) 62%, rgba(255, 255, 255, 0.08) 65%, rgba(255, 255, 255, 0.2) 67%, rgba(255, 255, 255, 0.45) 69%, rgba(255, 255, 255, 0.85) 70%, rgba(255, 255, 255, 0.85) 70.5%, rgba(255, 255, 255, 0.45) 71.5%, rgba(255, 255, 255, 0.2) 73%, rgba(255, 255, 255, 0.08) 75%, rgba(255, 255, 255, 0.03) 78%, transparent 82%);
}
[data-beam][data-theme="dark"] {
  --beam-conic-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 54%, rgba(255, 255, 255, 0.1) 57%, rgba(255, 255, 255, 0.3) 60%, rgba(255, 255, 255, 0.6) 63%, rgba(255, 255, 255, 0.75) 66%, rgba(255, 255, 255, 0.6) 69%, rgba(255, 255, 255, 0.3) 72%, rgba(255, 255, 255, 0.1) 75%, transparent 78%, transparent 100%);
  --beam-bloom-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 58%, rgba(255, 255, 255, 0.03) 62%, rgba(255, 255, 255, 0.08) 65%, rgba(255, 255, 255, 0.2) 67%, rgba(255, 255, 255, 0.45) 69%, rgba(255, 255, 255, 0.85) 70%, rgba(255, 255, 255, 0.85) 70.5%, rgba(255, 255, 255, 0.45) 71.5%, rgba(255, 255, 255, 0.2) 73%, rgba(255, 255, 255, 0.08) 75%, rgba(255, 255, 255, 0.03) 78%, transparent 82%);
}
[data-beam][data-theme="light"] {
  --beam-conic-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 54%, rgba(0, 0, 0, 0.08) 57%, rgba(0, 0, 0, 0.2) 60%, rgba(0, 0, 0, 0.4) 63%, rgba(0, 0, 0, 0.55) 66%, rgba(0, 0, 0, 0.4) 69%, rgba(0, 0, 0, 0.2) 72%, rgba(0, 0, 0, 0.08) 75%, transparent 78%, transparent 100%);
  --beam-bloom-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 58%, rgba(0, 0, 0, 0.02) 62%, rgba(0, 0, 0, 0.08) 65%, rgba(0, 0, 0, 0.2) 67%, rgba(0, 0, 0, 0.4) 69%, rgba(0, 0, 0, 0.6) 70%, rgba(0, 0, 0, 0.6) 70.5%, rgba(0, 0, 0, 0.4) 71.5%, rgba(0, 0, 0, 0.2) 73%, rgba(0, 0, 0, 0.08) 75%, rgba(0, 0, 0, 0.03) 78%, transparent 82%);
}

/* ---- line highlight (theme-dependent) ---- */

[data-beam][data-size="line"] {
  --beam-line-highlight: radial-gradient(
      ellipse calc(35px * var(--beam-w)) calc(28px * var(--beam-h)) at calc(var(--beam-x) * 100%) calc(100% + 2px),
      rgba(0, 0, 0, 0.6) 0%,
      rgba(0, 0, 0, 0.25) 35%,
      transparent 70%
    );
}
.dark [data-beam][data-size="line"] {
  --beam-line-highlight: radial-gradient(
        ellipse calc(24px * var(--beam-w)) calc(28px * var(--beam-h)) at calc(var(--beam-x) * 100%) calc(100% + 2px),
        rgba(255, 255, 255, 0.38) 0%,
        rgba(255, 255, 255, 0.12) 30%,
        transparent 65%
      );
}
[data-beam][data-size="line"][data-theme="dark"] {
  --beam-line-highlight: radial-gradient(
        ellipse calc(24px * var(--beam-w)) calc(28px * var(--beam-h)) at calc(var(--beam-x) * 100%) calc(100% + 2px),
        rgba(255, 255, 255, 0.38) 0%,
        rgba(255, 255, 255, 0.12) 30%,
        transparent 65%
      );
}
[data-beam][data-size="line"][data-theme="light"] {
  --beam-line-highlight: radial-gradient(
      ellipse calc(35px * var(--beam-w)) calc(28px * var(--beam-h)) at calc(var(--beam-x) * 100%) calc(100% + 2px),
      rgba(0, 0, 0, 0.6) 0%,
      rgba(0, 0, 0, 0.25) 35%,
      transparent 70%
    );
}

/* ---- per-variant color gradients (theme-independent for border/sm/md) ---- */

[data-beam][data-size="md"][data-variant="colorful"] {
  --beam-color-gradient: radial-gradient(ellipse 70px 40px at 33% -7.4%, rgb(255, 50, 100), transparent),
      radial-gradient(ellipse 60px 35px at 12% -5%, rgb(40, 140, 255), transparent),
      radial-gradient(ellipse 40px 70px at 2.1% 68.3%, rgb(50, 200, 80), transparent),
      radial-gradient(ellipse 20px 35px at 2.1% 68.3%, rgb(30, 185, 170), transparent),
      radial-gradient(ellipse 180px 32px at 74.4% 100%, rgb(100, 70, 255), transparent),
      radial-gradient(ellipse 85px 26px at 55% 100%, rgb(40, 140, 255), transparent),
      radial-gradient(ellipse 74px 32px at 93.9% 0%, rgb(255, 120, 40), transparent),
      radial-gradient(ellipse 26px 42px at 100% 27.1%, rgb(240, 50, 180), transparent),
      radial-gradient(ellipse 52px 48px at 100% 27.1%, rgb(180, 40, 240), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 63px 36px at 33% -7.4%, rgba(255, 50, 100, 0.45), transparent),
      radial-gradient(ellipse 54px 32px at 12% -5%, rgba(40, 140, 255, 0.45), transparent),
      radial-gradient(ellipse 36px 63px at 2.1% 68.3%, rgba(50, 200, 80, 0.45), transparent),
      radial-gradient(ellipse 18px 32px at 2.1% 68.3%, rgba(30, 185, 170, 0.45), transparent),
      radial-gradient(ellipse 162px 29px at 74.4% 100%, rgba(100, 70, 255, 0.45), transparent),
      radial-gradient(ellipse 77px 23px at 55% 100%, rgba(40, 140, 255, 0.45), transparent),
      radial-gradient(ellipse 67px 29px at 93.9% 0%, rgba(255, 120, 40, 0.45), transparent),
      radial-gradient(ellipse 23px 38px at 100% 27.1%, rgba(240, 50, 180, 0.45), transparent),
      radial-gradient(ellipse 47px 43px at 100% 27.1%, rgba(180, 40, 240, 0.45), transparent);
}
[data-beam][data-size="sm"][data-variant="colorful"] {
  --beam-color-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgb(50, 200, 80), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgb(30, 185, 170), transparent),
      radial-gradient(ellipse 59px 9px at 72% -3%, rgb(255, 120, 40), transparent),
      radial-gradient(ellipse 42px 7px at 74% 100%, rgb(100, 70, 255), transparent),
      radial-gradient(ellipse 10px 17px at 100% 27%, rgb(240, 50, 180), transparent),
      radial-gradient(ellipse 10px 18px at 100% 27%, rgb(180, 40, 240), transparent),
      radial-gradient(ellipse 5px 10px at 100% 27%, rgb(40, 140, 255), transparent),
      radial-gradient(ellipse 11px 12px at 100% 27%, rgb(255, 50, 100), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgba(50, 200, 80, 0.5), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgba(30, 185, 170, 0.45), transparent),
      radial-gradient(ellipse 59px 9px at 72% -3%, rgba(255, 120, 40, 0.35), transparent),
      radial-gradient(ellipse 42px 7px at 74% 100%, rgba(100, 70, 255, 0.35), transparent),
      radial-gradient(ellipse 10px 17px at 100% 27%, rgba(240, 50, 180, 0.3), transparent),
      radial-gradient(ellipse 10px 18px at 100% 27%, rgba(180, 40, 240, 0.4), transparent),
      radial-gradient(ellipse 5px 10px at 100% 27%, rgba(40, 140, 255, 0.3), transparent),
      radial-gradient(ellipse 11px 12px at 100% 27%, rgba(255, 50, 100, 0.3), transparent);
}

[data-beam][data-size="md"][data-variant="mono"] {
  --beam-color-gradient: radial-gradient(ellipse 70px 40px at 33% -7.4%, rgb(180, 180, 180), transparent),
      radial-gradient(ellipse 60px 35px at 12% -5%, rgb(140, 140, 140), transparent),
      radial-gradient(ellipse 40px 70px at 2.1% 68.3%, rgb(160, 160, 160), transparent),
      radial-gradient(ellipse 20px 35px at 2.1% 68.3%, rgb(130, 130, 130), transparent),
      radial-gradient(ellipse 180px 32px at 74.4% 100%, rgb(170, 170, 170), transparent),
      radial-gradient(ellipse 85px 26px at 55% 100%, rgb(150, 150, 150), transparent),
      radial-gradient(ellipse 74px 32px at 93.9% 0%, rgb(190, 190, 190), transparent),
      radial-gradient(ellipse 26px 42px at 100% 27.1%, rgb(145, 145, 145), transparent),
      radial-gradient(ellipse 52px 48px at 100% 27.1%, rgb(165, 165, 165), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 63px 36px at 33% -7.4%, rgba(180, 180, 180, 0.225), transparent),
      radial-gradient(ellipse 54px 32px at 12% -5%, rgba(140, 140, 140, 0.225), transparent),
      radial-gradient(ellipse 36px 63px at 2.1% 68.3%, rgba(160, 160, 160, 0.225), transparent),
      radial-gradient(ellipse 18px 32px at 2.1% 68.3%, rgba(130, 130, 130, 0.225), transparent),
